CREATE TABLE memory_entries (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    source_file TEXT NOT NULL,
    entry_date DATE NOT NULL,
    entry_type TEXT CHECK(entry_type IN ('daily_log', 'long_term', 'archive', 'system')),
    title TEXT,
    content TEXT NOT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE sqlite_sequence(name,seq);
CREATE VIRTUAL TABLE memory_fts USING fts5(
    content,
    title,
    source_file,
    entry_date,
    content='memory_entries',
    content_rowid='id'
)
/* memory_fts(content,title,source_file,entry_date) */;
CREATE TABLE IF NOT EXISTS 'memory_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'memory_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'memory_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'memory_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TRIGGER memory_insert AFTER INSERT ON memory_entries BEGIN
    INSERT INTO memory_fts(rowid, content, title, source_file, entry_date)
    SELECT new.id, new.content, new.title, new.source_file, new.entry_date;
END;
CREATE TRIGGER memory_delete AFTER DELETE ON memory_entries BEGIN
    DELETE FROM memory_fts WHERE rowid = old.id;
END;
CREATE TRIGGER memory_update AFTER UPDATE ON memory_entries BEGIN
    DELETE FROM memory_fts WHERE rowid = old.id;
    INSERT INTO memory_fts(rowid, content, title, source_file, entry_date)
    SELECT new.id, new.content, new.title, new.source_file, new.entry_date;
END;
CREATE INDEX idx_memory_date ON memory_entries(entry_date);
CREATE INDEX idx_memory_type ON memory_entries(entry_type);
CREATE INDEX idx_memory_source ON memory_entries(source_file);
CREATE TABLE tags (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    tag_name TEXT UNIQUE NOT NULL,
    tag_category TEXT
);
CREATE TABLE memory_tags (
    memory_id INTEGER,
    tag_id INTEGER,
    PRIMARY KEY (memory_id, tag_id),
    FOREIGN KEY (memory_id) REFERENCES memory_entries(id) ON DELETE CASCADE,
    FOREIGN KEY (tag_id) REFERENCES tags(id) ON DELETE CASCADE
);
CREATE TABLE search_history (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    query TEXT NOT NULL,
    results_count INTEGER,
    searched_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

